WITH fn AS (SELECT p.oid, p.proacl, p.proowner, pg_get_functiondef(p.oid) AS definition FROM pg_proc p WHERE p.oid = to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)')) SELECT audit_issue, detail FROM (SELECT 'function_missing'::text AS audit_issue, 'Thieu RPC adjust_shipment_items_v1(uuid,jsonb,text)'::text AS detail WHERE NOT EXISTS (SELECT 1 FROM fn) UNION ALL SELECT 'old_customer_filter_still_active', 'RPC van khoa ma theo customer_id dai dien cua chuyen' WHERE EXISTS (SELECT 1 FROM fn WHERE definition ILIKE '%p.customer_id IS NOT DISTINCT FROM v_shipment.customer_id%') UNION ALL SELECT 'shipment_date_guard_missing', 'RPC khong con kiem tra ma thuoc dung ngay cua chuyen' WHERE EXISTS (SELECT 1 FROM fn WHERE definition NOT ILIKE '%p.plan_date = v_shipment.shipment_date%') UNION ALL SELECT 'positive_plan_guard_missing', 'RPC khong con kiem tra planned_qty + backlog_qty > 0' WHERE EXISTS (SELECT 1 FROM fn WHERE definition NOT ILIKE '%COALESCE(p.planned_qty, 0) + COALESCE(p.backlog_qty, 0) > 0%') UNION ALL SELECT 'public_can_execute', 'PUBLIC van co quyen goi RPC' WHERE EXISTS (SELECT 1 FROM fn CROSS JOIN LATERAL aclexplode(COALESCE(fn.proacl, acldefault('f', fn.proowner))) acl WHERE acl.grantee = 0 AND acl.privilege_type = 'EXECUTE') UNION ALL SELECT 'anon_can_execute', 'anon van co quyen goi RPC' WHERE to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)') IS NOT NULL AND has_function_privilege('anon', 'public.adjust_shipment_items_v1(uuid,jsonb,text)', 'EXECUTE') UNION ALL SELECT 'authenticated_cannot_execute', 'authenticated khong co quyen goi RPC' WHERE to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)') IS NOT NULL AND NOT has_function_privilege('authenticated', 'public.adjust_shipment_items_v1(uuid,jsonb,text)', 'EXECUTE')) problems ORDER BY audit_issue;
